def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
    if wlan.isconnected():
        print("\nConnected! IP:", wlan.ifconfig()[0])
        return wlan.ifconfig()[0]
    else:
        print("\nFailed to connect to WiFi")
        return None


def compute_websocket_accept(key):
    GUID = "258EAFA5-E914-47DA-95CA-5AB5C11BE5C4"
    combined = key.strip() + GUID
    sha1_hash = hashlib.sha1(combined.encode()).digest()
    return binascii.b2a_base64(sha1_hash).decode().strip()


def parse_http_request(data):
    headers = {}
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    for line in lines[1:]:
        if ":" in line:
            key, value = line.split(":", 1)
            headers[key.strip().lower()] = value.strip()
    return request_line, headers


def send_websocket_handshake(client_socket, key):
    accept_key = compute_websocket_accept(key)
    response = (
        "HTTP/1.1 101 Switching Protocols\r\n"
        "Upgrade: websocket\r\n"
        "Connection: Upgrade\r\n"
        "Sec-WebSocket-Accept: " + accept_key + "\r\n"
        "\r\n"
    )
    client_socket.send(response.encode())


def decode_websocket_frame(data):
    if len(data) < 2:
        return None, None

    opcode = data[0] & 0x0F
    masked = (data[1] & 0x80) != 0
    payload_length = data[1] & 0x7F

    offset = 2

    if payload_length == 126:
        if len(data) < 4:
            return None, None
        payload_length = struct.unpack(">H", data[2:4])[0]
        offset = 4
    elif payload_length == 127:
        if len(data) < 10:
            return None, None
        payload_length = struct.unpack(">Q", data[2:10])[0]
        offset = 10

    if masked:
        if len(data) < offset + 4:
            return None, None
        mask_key = data[offset:offset + 4]
        offset += 4

    if len(data) < offset + payload_length:
        return None, None

    payload = data[offset:offset + payload_length]

    if masked:
        unmasked = bytearray(payload_length)
        for i in range(payload_length):
            unmasked[i] = payload[i] ^ mask_key[i % 4]
        payload = bytes(unmasked)

    return opcode, payload


def encode_websocket_frame(data, opcode=0x01):
    frame = bytearray()
    frame.append(0x80 | opcode)

    payload = data.encode("utf-8") if isinstance(data, str) else data
    length = len(payload)

    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack(">H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack(">Q", length))

    frame.extend(payload)
    return bytes(frame)


def send_to_client(client_socket, message):
    try:
        frame = encode_websocket_frame(message)
        client_socket.send(frame)
        return True
    except Exception as e:
        print("Error sending to client:", e)
        return False


def broadcast(message, exclude=None):
    clients_lock.acquire()
    disconnected = []
    for client in clients:
        if client != exclude:
            if not send_to_client(client, message):
                disconnected.append(client)
    for client in disconnected:
        if client in clients:
            clients.remove(client)
            try:
                client.close()
            except:
                pass
    clients_lock.release()


def get_state_json():
    return json.dumps({"type": "state_update", "state": device_state})


def handle_command(command, client_socket):
    global device_state

    action = command.get("action", "")
    response = {"type": "response", "action": action, "success": True}

    if action == "turn_on":
        device_state["power"] = True
        led.value(1)
        response["message"] = "Device turned ON"
        print("Action: Device turned ON")

    elif action == "turn_off":
        device_state["power"] = False
        led.value(0)
        response["message"] = "Device turned OFF"
        print("Action: Device turned OFF")

    elif action == "toggle":
        device_state["power"] = not device_state["power"]
        led.value(1 if device_state["power"] else 0)
        state_str = "ON" if device_state["power"] else "OFF"
        response["message"] = "Device toggled " + state_str
        print("Action: Device toggled", state_str)

    elif action == "set_brightness":
        brightness = command.get("value", 100)
        brightness = max(0, min(100, int(brightness)))
        device_state["brightness"] = brightness
        response["message"] = "Brightness set to " + str(brightness)
        print("Action: Brightness set to", brightness)

    elif action == "set_mode":
        mode = command.get("value", "normal")
        if mode in ["normal", "eco", "boost", "sleep"]:
            device_state["mode"] = mode
            response["message"] = "Mode set to " + mode
            print("Action: Mode set to", mode)
        else:
            response["success"] = False
            response["message"] = "Invalid mode: " + str(mode)

    elif action == "get_state":
        send_to_client(client_socket, get_state_json())
        return

    elif action == "restart":
        response["message"] = "Device restarting..."
        send_to_client(client_socket, json.dumps(response))
        time.sleep(1)
        machine.reset()
        return

    elif action == "ping":
        response["message"] = "pong"
        response["timestamp"] = time.ticks_ms()
        send_to_client(client_socket, json.dumps(response))
        return

    else:
        response["success"] = False
        response["message"] = "Unknown action: " + str(action)
        print("Unknown action:", action)

    send_to_client(client_socket, json.dumps(response))
    broadcast(get_state_json())


def handle_client(client_socket, client_address):
    print("New connection from:", client_address)

    try:
        data = client_socket.recv(1024)
        if not data:
            client_socket.close()
            return

        request_line, headers = parse_http_request(data)

        if "upgrade" in headers and headers["upgrade"].lower() == "websocket":
            ws_key = headers.get("sec-websocket-key", "")
            send_websocket_handshake(client_socket, ws_key)
            print("WebSocket handshake completed for:", client_address)

            clients_lock.acquire()
            clients.append(client_socket)
            clients_lock.release()

            send_to_client(client_socket, json.dumps({
                "type": "welcome",
                "message": "Connected to ESP32 IoT Controller",
                "state": device_state
            }))

            client_socket.settimeout(0.5)

            while True:
                try:
                    frame_data = client_socket.recv(4096)
                    if not frame_data:
                        print("Client disconnected:", client_address)
                        break

                    opcode, payload = decode_websocket_frame(frame_data)

                    if opcode is None:
                        continue

                    if opcode == 0x08:
                        print("Client sent close frame:", client_address)
                        close_frame = encode_websocket_frame(b"", opcode=0x08)
                        try:
                            client_socket.send(close_frame)
                        except:
                            pass
                        break

                    elif opcode == 0x09:
                        pong_frame = encode_websocket_frame(payload if payload else b"", opcode=0x0A)
                        client_socket.send(pong_frame)
                        continue

                    elif opcode == 0x0A:
                        continue

                    elif opcode == 0x01:
                        message = payload.decode("utf-8")
                        print("Received from", client_address, ":", message)

                        try:
                            command = json.loads(message)
                            handle_command(command, client_socket)
                        except ValueError:
                            error_response = json.dumps({
                                "type": "error",
                                "message": "Invalid JSON format"
                            })
                            send_to_client(client_socket, error_response)

                except OSError as e:
                    if e.args[0] == 110 or e.args[0] == 11:
                        continue
                    else:
                        print("Socket error:", e)
                        break
                except Exception as e:
                    print("Error handling frame:", e)
                    break

        else:
            html_response = generate_html_page()
            http_response = (
                "HTTP/1.1 200 OK\r\n"
                "Content-Type: text/html\r\n"
                "Content-Length: " + str(len(html_response)) + "\r\n"
                "Connection: close\r\n"
                "\r\n"
            ) + html_response
            client_socket.send(http_response.encode())

    except Exception as e:
        print("Error handling client:", e)

    finally:
        clients_lock.acquire()
        if client_socket in clients:
            clients.remove(client_socket)
        clients_lock.release()
        try:
            client_socket.close()
        except:
            pass
        print("Connection closed:", client_address)


